import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundRangeUntilOperatorRuleTest {
    private val spacingAroundRangeOperatorRuleAssertThat = assertThatRule { SpacingAroundRangeOperatorRule() }

    @Test
    fun `Given a ..< range then remove unexpected spacing`() {
        val code =
            """
            @OptIn(ExperimentalStdlibApi::class)
            fun foo(int: Int): String =
                when (int) {
                    in 10..<20 -> "A"
                    in 20..< 30 -> "B"
                    in 30 ..< 40 -> "C"
                    in 40 ..<50 -> "D"
                    else -> "unknown"
                }
            """.trimIndent()
        val formattedCode =
            """
            @OptIn(ExperimentalStdlibApi::class)
            fun foo(int: Int): String =
                when (int) {
                    in 10..<20 -> "A"
                    in 20..<30 -> "B"
                    in 30..<40 -> "C"
                    in 40..<50 -> "D"
                    else -> "unknown"
                }
            """.trimIndent()

        spacingAroundRangeOperatorRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(5, 17, "Unexpected spacing after \"..<\""),
                LintViolation(6, 14, "Unexpected spacing before \"..\""),
                LintViolation(6, 18, "Unexpected spacing after \"..<\""),
                LintViolation(7, 14, "Unexpected spacing before \"..\""),
            ).isFormattedAs(formattedCode)
    }
}
"}

